import type {
  CanvasParticle2D,
  CanvasParticle2DConstructor,
} from '@/component/particles/_base'
import { useEffect, useState } from 'react'
import type React from 'react'

/**
 * Render the nest particle effects.
 *
 * @param containerRef
 * @param options
 */
export default function useParticleEffect2D<T extends unknown = any>(
  containerRef: React.RefObject<HTMLElement> | null,
  Particle: CanvasParticle2DConstructor<T>,
  options?: T,
  visible = true,
): void {
  const [particle, setParticle] = useState<CanvasParticle2D | null>(null)

  useEffect(() => {
    if (containerRef == null || containerRef.current == null) return
    const particle = new Particle(containerRef.current, options)
    setParticle(particle)
    particle.start()
    return () => void particle.destroy()
  }, [containerRef, options, Particle])

  useEffect(() => {
    if (particle == null) return
    particle.toggleVisibility(visible)
  }, [particle, visible])
}
